import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  FaDownload, FaEye, FaBook, FaFilePdf, FaFileAlt, 
  FaQuestionCircle, FaHistory, FaArrowLeft, FaBookOpen, 
  FaClock, FaStar, FaSpinner, FaUser, FaSearch,
  FaFilter, FaFileWord, FaFilePowerpoint, FaFileImage,
  FaFileArchive, FaPrint
} from 'react-icons/fa';
import { coursesData, getSubjects } from '../data/coursesData';
import api from '../services/api'; // ✅ Import API service

const MaterialsPage = () => {
  const { courseId, yearId, semId, subjectId } = useParams();
  const navigate = useNavigate();
  
  const [subject, setSubject] = useState(null);
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedType, setSelectedType] = useState('all');
  const [downloading, setDownloading] = useState({});
  const [searchQuery, setSearchQuery] = useState('');
  const [courseInfo, setCourseInfo] = useState(null);
  const [error, setError] = useState(null); // ✅ Add error state

  // Material types (same as before)
  const materialTypes = [
    { id: 'all', name: 'All Materials', icon: <FaFilter />, color: '#6b7280' },
    { id: 'syllabus', name: 'Syllabus', icon: <FaBook />, color: '#3B82F6' },
    { id: 'notes', name: 'Notes', icon: <FaFileAlt />, color: '#10B981' },
    { id: 'pyq', name: 'PYQs', icon: <FaHistory />, color: '#8B5CF6' },
    { id: 'important', name: 'Imp Questions', icon: <FaQuestionCircle />, color: '#F59E0B' },
    { id: 'lab', name: 'Lab Manuals', icon: <FaBookOpen />, color: '#EF4444' },
    { id: 'assignment', name: 'Assignments', icon: <FaFilePdf />, color: '#EC4899' }
  ];

  // ✅ FIXED: Fetch real data from backend
  const fetchMaterialsFromBackend = async () => {
    try {
      setLoading(true);
      setError(null);
      
      // Build query params
      const params = {
        course: courseId,
        year: yearId,
        semester: semId,
        subject: subjectId,
        status: 'approved' // Sirf approved content
      };
      
      console.log('Fetching materials with params:', params);
      
      // ✅ API call to get approved materials
      const response = await api.get('/notes', { params });
      
      console.log('API Response:', response.data);
      
      if (response.data && response.data.notes) {
        // Transform backend data to match frontend format
        const transformedMaterials = response.data.notes.map(note => ({
          id: note.id,
          title: note.title,
          type: note.type || 'notes',
          description: note.description || '',
          fileSize: note.file_size || '1.2 MB',
          pages: note.pages || 10,
          uploadDate: new Date(note.created_at).toLocaleDateString('en-IN', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
          }),
          downloads: note.download_count || 0,
          views: note.view_count || 0,
          rating: note.rating || 4.5,
          fileUrl: note.file_url || '#',
          fileType: note.file_type || 'pdf',
          user: note.uploader_name || 'Admin',
          isNew: new Date(note.created_at) > new Date(Date.now() - 7*24*60*60*1000) // Last 7 days
        }));
        
        setMaterials(transformedMaterials);
      } else {
        // Fallback to mock data if no data from backend
        console.log('No data from backend, using mock data');
        if (subject) {
          const mockMaterials = generateMockMaterials(subject);
          setMaterials(mockMaterials);
        }
      }
      
    } catch (error) {
      console.error('Error fetching materials:', error);
      setError('Failed to load materials. Using sample data.');
      
      // Fallback to mock data on error
      if (subject) {
        const mockMaterials = generateMockMaterials(subject);
        setMaterials(mockMaterials);
      }
    } finally {
      setLoading(false);
    }
  };

  // ✅ Refresh function (call after approval)
  const refreshMaterials = () => {
    fetchMaterialsFromBackend();
  };

  // Fetch subject data and materials
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      
      try {
        // Get subject info from local data
        const subjects = getSubjects(parseInt(courseId), parseInt(yearId), parseInt(semId));
        const foundSubject = subjects.find(sub => sub.id === parseInt(subjectId));
        
        if (foundSubject) {
          setSubject(foundSubject);
          setCourseInfo(coursesData[courseId]);
          
          // ✅ Fetch real materials from backend
          await fetchMaterialsFromBackend();
        } else {
          setError('Subject not found');
          setLoading(false);
        }
      } catch (error) {
        console.error('Error:', error);
        setError('Failed to load subject');
        setLoading(false);
      }
    };
    
    loadData();
    
    // ✅ Auto-refresh every 30 seconds (for new approvals)
    const interval = setInterval(() => {
      if (subject) {
        console.log('Auto-refreshing materials...');
        fetchMaterialsFromBackend();
      }
    }, 30000);
    
    return () => clearInterval(interval);
  }, [courseId, yearId, semId, subjectId]);

  // Generate mock materials (fallback)
  const generateMockMaterials = (subjectData) => {
    // ... (your existing mock data generation code)
    const baseMaterials = [
      {
        id: 1,
        title: `${subjectData.name} Complete Syllabus`,
        type: 'syllabus',
        description: `Official syllabus for ${subjectData.name} with unit-wise distribution and marking scheme`,
        fileSize: '1.2 MB',
        pages: 12,
        uploadDate: '15 Jan 2024',
        downloads: subjectData.materials * 10 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 20 + Math.floor(Math.random() * 100),
        rating: subjectData.rating,
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Admin',
        isNew: true
      },
      // ... rest of your mock data
    ];
    
    return baseMaterials;
  };

  // ✅ Enhanced handleDownload to track in backend
  const handleDownload = async (material) => {
    setDownloading(prev => ({ ...prev, [material.id]: true }));
    
    try {
      // Track download in backend
      if (material.id && typeof material.id === 'number') {
        await api.post(`/notes/${material.id}/download`).catch(err => 
          console.log('Download tracking failed:', err)
        );
      }
      
      // Your existing download logic
      // ... (keep your existing download code)
      
    } catch (error) {
      console.error('Download error:', error);
    } finally {
      setTimeout(() => {
        setDownloading(prev => ({ ...prev, [material.id]: false }));
      }, 1500);
    }
  };

  // ✅ Manual refresh button handler
  const handleManualRefresh = () => {
    refreshMaterials();
  };

  // Rest of your existing functions (handlePreview, handleBack, etc.)
  const handlePreview = (material) => {
    // ... (your existing preview code)
  };

  const handleBack = () => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semId}`);
  };

  // Filter materials
  const filteredMaterials = materials.filter(material => {
    const matchesType = selectedType === 'all' || material.type === selectedType;
    const matchesSearch = searchQuery === '' ||
      material.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      material.description.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesType && matchesSearch;
  });

  // Get file icon
  const getFileIcon = (fileType) => {
    const type = fileType?.toLowerCase() || 'pdf';
    if (type.includes('pdf')) return <FaFilePdf style={{ color: '#ef4444' }} />;
    if (type.includes('doc')) return <FaFileWord style={{ color: '#2563eb' }} />;
    if (type.includes('ppt')) return <FaFilePowerpoint style={{ color: '#f97316' }} />;
    return <FaFileAlt style={{ color: '#6b7280' }} />;
  };

  // Calculate stats
  const getMaterialStats = () => {
    const stats = {};
    materialTypes.forEach(type => {
      if (type.id !== 'all') {
        stats[type.id] = materials.filter(m => m.type === type.id).length;
      }
    });
    return stats;
  };

  const materialStats = getMaterialStats();

  // Styles (keep your existing styles)
  const styles = {
    // ... (your existing styles object)
  };

  if (loading) {
    return (
      <div style={styles.container}>
        <div style={styles.innerContainer}>
          <div style={{ textAlign: 'center', padding: '100px' }}>
            <div style={{
              width: '50px',
              height: '50px',
              border: '5px solid #f3f4f6',
              borderTop: '5px solid #4f46e5',
              borderRadius: '50%',
              margin: '0 auto 20px',
              animation: 'spin 1s linear infinite'
            }}></div>
            <h3 style={{ color: '#6b7280' }}>Loading Materials...</h3>
          </div>
        </div>
      </div>
    );
  }

  if (!subject) {
    return (
      <div style={styles.container}>
        <div style={styles.innerContainer}>
          <button style={styles.backButton} onClick={() => navigate(-1)}>
            <FaArrowLeft /> Back
          </button>
          <div style={{ textAlign: 'center', padding: '100px' }}>
            <h2>Subject not found</h2>
            <p>The requested subject could not be found.</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
      
      <div style={styles.innerContainer}>
        
        {/* Back Button and Refresh Button */}
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
          <button style={styles.backButton} onClick={handleBack}>
            <FaArrowLeft /> Back to Subjects
          </button>
          
          {/* ✅ Added Refresh Button */}
          <button
            style={{
              ...styles.backButton,
              background: '#10b981',
              width: 'auto'
            }}
            onClick={handleManualRefresh}
          >
            <FaSpinner style={{ animation: loading ? 'spin 1s linear infinite' : 'none' }} />
            {loading ? 'Refreshing...' : 'Refresh Materials'}
          </button>
        </div>
        
        {/* Error Message */}
        {error && (
          <div style={{
            background: '#fee2e2',
            color: '#dc2626',
            padding: '15px',
            borderRadius: '8px',
            marginBottom: '20px',
            textAlign: 'center'
          }}>
            {error}
          </div>
        )}
        
        {/* Subject Header */}
        <div style={styles.subjectHeader}>
          {/* ... your existing subject header JSX ... */}
        </div>

        {/* Search Bar */}
        {/* ... your existing search bar JSX ... */}

        {/* Filter Buttons */}
        {/* ... your existing filter buttons JSX ... */}

        {/* Materials Grid */}
        {filteredMaterials.length === 0 ? (
          <div style={{
            background: 'white',
            padding: '60px 20px',
            borderRadius: '12px',
            textAlign: 'center',
            boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
          }}>
            <div style={{ fontSize: '60px', marginBottom: '20px', opacity: '0.5' }}>📭</div>
            <h3 style={{ fontSize: '24px', fontWeight: '600', color: '#6b7280', marginBottom: '10px' }}>
              No materials found
            </h3>
            <p style={{ color: '#9ca3af', fontSize: '16px', marginBottom: '30px' }}>
              {searchQuery 
                ? `No materials match "${searchQuery}"`
                : 'No approved materials available yet. Check back later or upload new materials.'}
            </p>
            <button
              style={{
                padding: '12px 30px',
                background: '#4f46e5',
                color: 'white',
                border: 'none',
                borderRadius: '8px',
                cursor: 'pointer',
                fontWeight: '600',
                fontSize: '16px',
                marginRight: '10px'
              }}
              onClick={() => navigate('/upload')}
            >
              Upload Materials
            </button>
            {searchQuery && (
              <button
                style={{
                  padding: '12px 30px',
                  background: '#6b7280',
                  color: 'white',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontWeight: '600',
                  fontSize: '16px'
                }}
                onClick={() => setSearchQuery('')}
              >
                Clear Search
              </button>
            )}
          </div>
        ) : (
          <div style={{
            background: 'white',
            padding: '30px',
            borderRadius: '12px',
            boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
              <h3 style={{ fontSize: '24px', fontWeight: '700', color: '#1f2937' }}>
                {selectedType === 'all' ? 'All Study Materials' : materialTypes.find(t => t.id === selectedType)?.name}
              </h3>
              <span style={{ color: '#6b7280' }}>
                {filteredMaterials.length} material{filteredMaterials.length !== 1 ? 's' : ''}
              </span>
            </div>
            
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))',
              gap: '25px'
            }}>
              {filteredMaterials.map((material) => {
                const typeInfo = materialTypes.find(t => t.id === material.type);
                
                return (
                  <div
                    key={material.id}
                    style={{
                      border: '1px solid #e5e7eb',
                      borderRadius: '12px',
                      overflow: 'hidden',
                      transition: 'all 0.4s ease',
                      background: 'white'
                    }}
                  >
                    {/* ... your existing material card JSX ... */}
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

